import fs from "node:fs";
import { createClient } from "@supabase/supabase-js";
import Papa from "papaparse";

const CSV_PATH =
  "c:\\Users\\sinan\\Downloads\\Outscraper-20260720122512s63_driving_school_+1(Generated by Outscraper ©).csv";

function readEnv(path) {
  const env = {};
  for (const line of fs.readFileSync(path, "utf8").split(/\r?\n/)) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("#")) continue;
    const [key, ...rest] = trimmed.split("=");
    if (!key || rest.length === 0) continue;
    env[key.trim()] = rest.join("=").trim().replace(/^['"]|['"]$/g, "");
  }
  return env;
}

function clean(value) {
  const str = String(value ?? "").trim();
  if (!str || str.toLowerCase() === "none" || str.toLowerCase() === "null") return "";
  return str;
}

function validUrl(value) {
  const str = clean(value);
  return /^https?:\/\//i.test(str) ? str : "";
}

function bestPhone(row) {
  return clean(row.contact_phone) || clean(row.company_phone) || clean(row.phone);
}

function notesFor(row) {
  const parts = [
    clean(row.title) && `Title: ${clean(row.title)}`,
    clean(row.address) && `Address: ${clean(row.address)}`,
    clean(row.rating) && `Google rating: ${clean(row.rating)} (${clean(row.reviews) || "0"} reviews)`,
    clean(row.email?.emails_validator?.status) &&
      `Email status: ${clean(row.email.emails_validator.status)}`,
    clean(row["email.emails_validator.status"]) &&
      `Email status: ${clean(row["email.emails_validator.status"])}`,
    clean(row.contact_linkedin) && `LinkedIn: ${clean(row.contact_linkedin)}`,
    clean(row.company_linkedin) && `Company LinkedIn: ${clean(row.company_linkedin)}`,
    clean(row.location_link) && `Google Maps: ${clean(row.location_link)}`,
    clean(row.place_id) && `Place ID: ${clean(row.place_id)}`,
  ].filter(Boolean);

  return parts.join("\n");
}

