function normalizePlace(value) {
  return clean(value).toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
}

function isLocalRow(row) {
  const city = normalizePlace(row.city);
  const address = normalizePlace(row.address);
  const postalCode = clean(row.postal_code).toUpperCase();

  if (postalCode.startsWith("NR")) return true;
  if (city && ALLOWED_TOWNS.has(city)) return true;

  for (const town of ALLOWED_TOWNS) {
    if (city && city !== "norwich" && town === "norwich") continue;
    if (town && address.includes(town)) return true;
  }

  return false;
}

function mapRow(row) {
  if (!isLocalRow(row)) return null;

  const contactName =
    clean(row.full_name) ||
    [clean(row.first_name), clean(row.last_name)].filter(Boolean).join(" ") ||
    clean(row.name_for_emails);
  const businessName = clean(row.name) || clean(row.company_name) || contactName;

  if (!businessName) return null;

  return {
    board_id: "instructors",
    stage: "Not contacted",
    owner_email: null,
    next_action: "Initial outreach",
    next_action_date: null,
    created_by: "outscraper-import",
    data: {
      business_name: businessName,
      contact_name: contactName,
      mobile: bestPhone(row),
      email: clean(row.email),
      website: validUrl(row.website),
      city: clean(row.city) || "Norwich",
      source: "Outscraper",
      referred_by: "",
      channel: bestPhone(row) ? "Phone" : clean(row.email) ? "Email" : "",
      date_first_contacted: "",
      date_last_touch: "",
      network_size: clean(row["company_insights.employees"]),
      is_champion: false,
      subscription_status: "None",
      notes: notesFor(row),
    },
  };
}

function keyFor(item) {
  return [
    item.data.business_name.toLowerCase(),
    String(item.data.contact_name || "").toLowerCase(),
    String(item.data.email || "").toLowerCase(),
    String(item.data.mobile || "").replace(/\D/g, ""),
  ].join("|");
}

const env = readEnv(".env.local");
const supabaseUrl = env.NEXT_PUBLIC_SUPABASE_URL;
const serviceKey = env.SUPABASE_SERVICE_ROLE_KEY;

if (!supabaseUrl || !serviceKey) {
  throw new Error("NEXT_PUBLIC_SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY are required in .env.local");
}

const csv = fs.readFileSync(CSV_PATH, "utf8");
const parsed = Papa.parse(csv, { header: true, skipEmptyLines: true });
if (parsed.errors.length) {
  console.warn("CSV parse warnings:", parsed.errors.slice(0, 5));
}

const seen = new Set();
const items = [];
let skippedNonLocalRows = 0;
for (const row of parsed.data) {
  if (!isLocalRow(row)) {
    skippedNonLocalRows++;
    continue;
  }
  const item = mapRow(row);
  if (!item) continue;
  const key = keyFor(item);
  if (seen.has(key)) continue;
  seen.add(key);
  items.push(item);
}

const supabase = createClient(supabaseUrl, serviceKey, {
  auth: { autoRefreshToken: false, persistSession: false },
});

const { count: beforeCount, error: beforeError } = await supabase
  .from("ops_items")
  .select("id", { count: "exact", head: true })
  .eq("board_id", "instructors");
if (beforeError) throw beforeError;

const { error: deleteError } = await supabase
  .from("ops_items")
  .delete()
  .eq("board_id", "instructors");
if (deleteError) throw deleteError;

for (let i = 0; i < items.length; i += 500) {
  const batch = items.slice(i, i + 500);
  const { error } = await supabase.from("ops_items").insert(batch);
  if (error) throw error;
}

const { count: afterCount, error: afterError } = await supabase
  .from("ops_items")
  .select("id", { count: "exact", head: true })
  .eq("board_id", "instructors");
if (afterError) throw afterError;

console.log(
  JSON.stringify(
    {
      deleted_existing_instructor_rows: beforeCount ?? 0,
      parsed_csv_rows: parsed.data.length,
      inserted_instructor_rows: afterCount ?? 0,
      skipped_non_local_rows: skippedNonLocalRows,
      skipped_duplicate_or_blank_rows: parsed.data.length - skippedNonLocalRows - items.length,
    },
    null,
    2
  )
);
